  }

  const STATUS_VARIANT: Record<string, 'neutral' | 'info' | 'warning' | 'success' | 'error'> = {
    applied: 'neutral', screening: 'info', interview: 'warning', offer: 'info', hired: 'success', rejected: 'error',
