                <Icon className={`h-3.5 w-3.5 ${color}`} /> {label}
              </span>
            ))}
          </div>
        </div>
      )}

      {/* Timesheet Tab */}
      {activeTab === 'timesheet' && (
        <div className="space-y-4">
          {/* Summary Row */}
          <div className="grid grid-cols-2 sm:grid-cols-3 lg:grid-cols-6 gap-3">
            <div className="bg-gradient-to-br from-gray-900 to-gray-800 rounded-xl p-4 text-white">
              <p className="text-2xl font-bold">{summary.totalWorkHours}h</p>
              <p className="text-[10px] text-gray-400 mt-0.5">{t('totalHours')}</p>
            </div>
            <div className="bg-white border border-gray-200 rounded-xl p-4">
              <p className="text-2xl font-bold text-cg-dark">{summary.totalWorkDays}</p>
              <p className="text-[10px] text-gray-400 mt-0.5">Work Days</p>
            </div>
            <div className="bg-white border border-gray-200 rounded-xl p-4">
              <p className="text-2xl font-bold text-amber-500">{summary.lateDays}</p>
              <p className="text-[10px] text-gray-400 mt-0.5">Late Days</p>
            </div>
            <div className="bg-white border border-gray-200 rounded-xl p-4">
              <p className="text-2xl font-bold text-red-500">{summary.absentDays}</p>
              <p className="text-[10px] text-gray-400 mt-0.5">Absent Days</p>
            </div>
            <div className="bg-white border border-gray-200 rounded-xl p-4">
              <p className="text-2xl font-bold text-sky-500">{summary.leaveDays}</p>
              <p className="text-[10px] text-gray-400 mt-0.5">Leave Days</p>
            </div>
            <div className="bg-white border border-gray-200 rounded-xl p-4">
              <p className="text-2xl font-bold text-cg-red">{summary.totalOvertimeHours}h</p>
              <p className="text-[10px] text-gray-400 mt-0.5">OT Hours</p>
            </div>
          </div>

          {/* Full Log */}
          <Card>
            <CardHeader className="pb-3">
              <div className="flex items-center justify-between">
                <CardTitle className="text-base">Time Result</CardTitle>
                <span className="text-xs text-gray-400">Feb 2026</span>
              </div>
            </CardHeader>
            <CardContent className="p-0">
              {/* Mobile cards */}
              <div className="sm:hidden divide-y">
                {attendance.map((rec) => {
                  const config = STATUS_CONFIG[rec.status] || STATUS_CONFIG.present;
                  return (
                    <div key={rec.id} className="px-4 py-3 flex items-center justify-between">
                      <div>
                        <p className="text-sm font-medium">{rec.dayOfWeek} <span className="text-gray-400 text-xs">{rec.date}</span></p>
                        <p className="text-xs text-gray-500 font-mono">
                          {rec.checkIn || '--:--'} - {rec.checkOut || '--:--'}
                        </p>
                      </div>
                      <div className="text-right flex items-center gap-2">
                        {rec.workHours > 0 && <span className="text-sm font-mono font-medium">{rec.workHours}h</span>}
                        <Badge variant={config.variant} className="capitalize text-[10px]">{rec.status}</Badge>
                      </div>
                    </div>
                  );
                })}
              </div>
              {/* Desktop table */}
              <div className="hidden sm:block overflow-x-auto">
                <table className="w-full text-sm">
                  <thead>
                    <tr className="border-b bg-gray-50/50">
                      <th className="text-left py-3 px-4 text-xs font-medium text-gray-400 uppercase">Date</th>
                      <th className="text-left py-3 px-4 text-xs font-medium text-gray-400 uppercase">{t('shift')}</th>
                      <th className="text-center py-3 px-4 text-xs font-medium text-gray-400 uppercase">In</th>
                      <th className="text-center py-3 px-4 text-xs font-medium text-gray-400 uppercase">Out</th>
                      <th className="text-center py-3 px-4 text-xs font-medium text-gray-400 uppercase">Work</th>
                      <th className="text-center py-3 px-4 text-xs font-medium text-gray-400 uppercase">OT</th>
                      <th className="text-center py-3 px-4 text-xs font-medium text-gray-400 uppercase">Location</th>
                      <th className="text-center py-3 px-4 text-xs font-medium text-gray-400 uppercase">Status</th>
                    </tr>
                  </thead>
                  <tbody>
                    {attendance.map((rec) => {
                      const config = STATUS_CONFIG[rec.status] || STATUS_CONFIG.present;
                      return (
                        <tr key={rec.id} className="border-b last:border-0 hover:bg-gray-50/50">
                          <td className="py-3 px-4">
                            <span className="font-medium">{rec.dayOfWeek}</span>
                            <span className="text-gray-400 ml-2 text-xs">{rec.date}</span>
                          </td>
                          <td className="py-3 px-4 text-gray-500 text-xs">{rec.shift}</td>
                          <td className="py-3 px-4 text-center font-mono text-xs">{rec.checkIn || '-'}</td>
                          <td className="py-3 px-4 text-center font-mono text-xs">{rec.checkOut || '-'}</td>
                          <td className="py-3 px-4 text-center">{rec.workHours > 0 ? `${rec.workHours}h` : '-'}</td>
                          <td className="py-3 px-4 text-center">
                            {rec.overtimeHours > 0 ? <span className="text-cg-red font-medium">+{rec.overtimeHours}h</span> : '-'}
                          </td>
                          <td className="py-3 px-4 text-center text-xs text-gray-400">{rec.location || '-'}</td>
                          <td className="py-3 px-4 text-center">
                            <Badge variant={config.variant} className="capitalize">{rec.status}</Badge>
                          </td>
                        </tr>
                      );
                    })}
                  </tbody>
                </table>
              </div>
            </CardContent>
          </Card>
        </div>
      )}

      {/* Correction Tab */}
      {activeTab === 'correction' && (
        <div className="space-y-4">
          {/* New Correction Button */}
          <div className="flex justify-end">
            <Button onClick={() => setShowCorrectionModal(true)}>
              <FileEdit className="h-4 w-4 mr-2" />
              New Correction Request
            </Button>
          </div>

          {/* Correction History */}
          <Card>
            <CardHeader className="pb-3">
              <CardTitle className="text-base">Correction Requests</CardTitle>
            </CardHeader>
            <CardContent>
              {corrections.length === 0 ? (
                <div className="py-12 text-center">
                  <FileEdit className="h-10 w-10 text-gray-300 mx-auto mb-3" />
                  <p className="text-sm text-gray-400">No correction requests yet</p>
                </div>
              ) : (
                <div className="space-y-3">
                  {corrections.map((req) => (
                    <div
                      key={req.id}
                      className="flex items-start gap-4 p-4 bg-gray-50 rounded-xl hover:bg-gray-100/80 transition-colors"
                    >
                      <div className={`flex-shrink-0 w-10 h-10 rounded-lg flex items-center justify-center ${
                        req.status === 'approved' ? 'bg-emerald-100 text-emerald-600' :
                        req.status === 'rejected' ? 'bg-red-100 text-red-600' :
                        'bg-amber-100 text-amber-600'
                      }`}>
                        {req.status === 'approved' ? <CheckCircle className="h-5 w-5" /> :
                         req.status === 'rejected' ? <XCircle className="h-5 w-5" /> :
                         <Clock className="h-5 w-5" />}
                      </div>
                      <div className="flex-1 min-w-0">
                        <div className="flex items-center gap-2 flex-wrap">
                          <span className="text-sm font-medium text-cg-dark">{req.date}</span>
                          <Badge variant={
                            req.status === 'approved' ? 'success' :
                            req.status === 'rejected' ? 'error' : 'warning'
                          } className="capitalize">{req.status}</Badge>
                        </div>
                        <p className="text-xs text-gray-500 mt-1">
                          <span className="capitalize">{req.type.replace(/-/g, ' ')}</span>
                          {req.originalTime && <> | Original: <span className="font-mono">{req.originalTime}</span></>}
                          {' '} | Corrected: <span className="font-mono font-medium">{req.correctedTime}</span>
                        </p>
                        <p className="text-xs text-gray-400 mt-1">{req.reason}</p>
                        {req.approvedBy && (
                          <p className="text-[10px] text-gray-400 mt-1">Approved by {req.approvedBy}</p>
                        )}
                      </div>
                      <ChevronRight className="h-4 w-4 text-gray-300 flex-shrink-0 mt-3" />
                    </div>
                  ))}
                </div>
              )}
            </CardContent>
          </Card>
        </div>
      )}

      {/* ===== CORRECTION REQUEST MODAL ===== */}
      <Modal open={showCorrectionModal} onClose={() => setShowCorrectionModal(false)} title="Time Correction Request">
        <div className="space-y-4">
          <FormField
            label="Date"
            name="corrDate"
            type="date"
            value={correctionForm.date}
            onChange={(v) => setCorrectionForm((p) => ({ ...p, date: v }))}
            required
          />
          <FormField
            label="Correction Type"
            name="corrType"
            type="select"
            value={correctionForm.type}
            onChange={(v) => setCorrectionForm((p) => ({ ...p, type: v as TimeCorrectionRequest['type'] }))}
            options={[
              { value: 'forgot-clock', label: 'Forgot to Clock In/Out' },
              { value: 'missing-checkin', label: 'Missing Check-in' },
              { value: 'missing-checkout', label: 'Missing Check-out' },
              { value: 'wrong-time', label: 'Wrong Time Recorded' },
            ]}
          />
          <FormField
            label="Corrected Time"
            name="corrTime"
            value={correctionForm.correctedTime}
            placeholder="e.g. 09:00"
            onChange={(v) => setCorrectionForm((p) => ({ ...p, correctedTime: v }))}
            required
          />
          <FormField
            label="Reason"
            name="corrReason"
            type="textarea"
            value={correctionForm.reason}
            placeholder="Explain why the correction is needed..."
            onChange={(v) => setCorrectionForm((p) => ({ ...p, reason: v }))}
            required
          />
        </div>
        <div className="flex justify-end gap-3 mt-6">
          <Button variant="outline" onClick={() => setShowCorrectionModal(false)}>{tCommon('cancel')}</Button>
          <Button
            onClick={handleCorrectionSubmit}
            disabled={!correctionForm.date || !correctionForm.correctedTime || !correctionForm.reason}
          >
            Submit Request
          </Button>
        </div>
      </Modal>
    </div>
  );
}

'use client';

import { useState, useRef, useCallback } from 'react';
import { useTranslations } from 'next-intl';
import {
  Upload,
  FileText,
  Camera,
  CheckCircle,
  AlertTriangle,
  AlertCircle,
  Info,
  Clock,
  DollarSign,
  Receipt,
  Send,
  Save,
  X,
  Loader2,
  Check,
  ChevronRight,
  Plus,
  Eye,
  FileCheck,
  Heart,
} from 'lucide-react';
import { Card, CardHeader, CardTitle, CardContent, CardFooter } from '@/components/ui/card';
import { Badge } from '@/components/ui/badge';
import { Button } from '@/components/ui/button';
import { Tabs } from '@/components/ui/tabs';
import { FormField } from '@/components/ui/form-field';
import { Modal } from '@/components/ui/modal';
import { Skeleton } from '@/components/ui/skeleton';
import {
  useMedicalClaims,
  DISEASE_CATEGORIES,
  type MedicalClaimStatus,
  type MedicalClaim,
  type DiseaseCategory,
} from '@/hooks/use-medical-claims';
import { formatCurrency, formatDate } from '@/lib/date';
import { useToast } from '@/components/ui/toast';

// --- Constants ---

const STATUS_VARIANT: Record<MedicalClaimStatus, 'neutral' | 'info' | 'warning' | 'success' | 'error'> = {
  draft: 'neutral',
  submitted: 'info',
  pending_manager: 'warning',
  pending_hr: 'warning',
  processing: 'warning',
  approved: 'success',
  rejected: 'error',
};

const MAX_FILE_SIZE = 10 * 1024 * 1024;
const ACCEPTED_TYPES = ['image/jpeg', 'image/png', 'application/pdf'];

// --- Helpers ---

function formatFileSize(bytes: number): string {
  if (bytes < 1024) return `${bytes} B`;
  if (bytes < 1024 * 1024) return `${(bytes / 1024).toFixed(1)} KB`;
  return `${(bytes / (1024 * 1024)).toFixed(1)} MB`;
}

function getCategoryLabel(cat: DiseaseCategory): string {
  return DISEASE_CATEGORIES.find((c) => c.value === cat)?.labelEn ?? cat;
}

// --- Types ---

type ActiveTab = 'overview' | 'newClaim' | 'history';
type WizardStep = 1 | 2 | 3;
type StatusFilter = 'all' | 'pending' | 'approved' | 'rejected';

interface ClaimForm {
  diseaseCategory: DiseaseCategory | '';
  diseaseDetails: string;
  hospitalName: string;
  treatmentDate: string;
  receiptAmount: string;
  claimAmount: string;
  remarks: string;
}

interface DocumentState {
  receipt: File | null;
  medicalCert: File | null;
  other: File[];
}

interface DragOverState {
  receipt: boolean;
  medicalCert: boolean;
  other: boolean;
}

interface FileErrorState {
  receipt: string;
  medicalCert: string;
  other: string;
}

const INITIAL_FORM: ClaimForm = {
  diseaseCategory: '',
  diseaseDetails: '',
  hospitalName: '',
  treatmentDate: '',
  receiptAmount: '',
  claimAmount: '',
  remarks: '',
};

const INITIAL_DOCUMENTS: DocumentState = { receipt: null, medicalCert: null, other: [] };
const INITIAL_DRAG: DragOverState = { receipt: false, medicalCert: false, other: false };
const INITIAL_ERRORS: FileErrorState = { receipt: '', medicalCert: '', other: '' };

// --- Component ---

export function MedicalClaimsPage() {
  const t = useTranslations();
  const { toast } = useToast();
  const { claims, summary, loading, stats, createClaim, addDocument, submitClaim, saveDraft } = useMedicalClaims();

  // Tab and wizard state
  const [activeTab, setActiveTab] = useState<ActiveTab>('overview');
  const [step, setStep] = useState<WizardStep>(1);

  // Form state
  const [form, setForm] = useState<ClaimForm>(INITIAL_FORM);
  const [documents, setDocuments] = useState<DocumentState>(INITIAL_DOCUMENTS);
  const [dragOver, setDragOver] = useState<DragOverState>(INITIAL_DRAG);
  const [fileErrors, setFileErrors] = useState<FileErrorState>(INITIAL_ERRORS);
  const [submitting, setSubmitting] = useState(false);

  // History state
  const [statusFilter, setStatusFilter] = useState<StatusFilter>('all');
  const [detailClaim, setDetailClaim] = useState<MedicalClaim | null>(null);

  // File refs
  const receiptRef = useRef<HTMLInputElement>(null);
  const certRef = useRef<HTMLInputElement>(null);
  const otherRef = useRef<HTMLInputElement>(null);

  // --- Validation ---

  const validateFile = useCallback((file: File): string => {
    if (!ACCEPTED_TYPES.includes(file.type)) return 'File type not supported. Please upload JPG, PNG, or PDF.';
    if (file.size > MAX_FILE_SIZE) return 'File too large. Maximum size is 10MB.';
    return '';
  }, []);

  const validateStep1 = useCallback((): boolean => {
    if (!form.diseaseCategory) return false;
    if (!form.hospitalName.trim()) return false;
    if (!form.treatmentDate) return false;
    const treatDate = new Date(form.treatmentDate);
    if (treatDate >= new Date()) return false;
    const amount = parseFloat(form.receiptAmount);
    if (!amount || amount <= 0) return false;
    return true;
  }, [form]);

  const validateStep2 = useCallback((): boolean => {
    return documents.receipt !== null && documents.medicalCert !== null;
  }, [documents]);

  // --- Form helpers ---

  const updateForm = useCallback((field: keyof ClaimForm, value: string) => {
    setForm((prev) => {
      const next = { ...prev, [field]: value };
      // Auto-fill claim amount from receipt, capped at remaining
      if (field === 'receiptAmount') {
        const receiptNum = parseFloat(value) || 0;
        const capped = Math.min(receiptNum, summary.remainingAmount);
        next.claimAmount = capped > 0 ? String(capped) : '';
      }
      return next;
    });
  }, [summary.remainingAmount]);

  const handleFileSelect = useCallback(
    (zone: 'receipt' | 'medicalCert' | 'other', files: FileList | null) => {
      if (!files || files.length === 0) return;
      if (zone === 'other') {
        const validFiles: File[] = [];
        for (let i = 0; i < files.length; i++) {
          const err = validateFile(files[i]);
          if (err) {
            setFileErrors((prev) => ({ ...prev, other: err }));
            return;
          }
          validFiles.push(files[i]);
        }
        setFileErrors((prev) => ({ ...prev, other: '' }));
        setDocuments((prev) => ({ ...prev, other: [...prev.other, ...validFiles] }));
      } else {
        const file = files[0];
        const err = validateFile(file);
        if (err) {
          setFileErrors((prev) => ({ ...prev, [zone]: err }));
          return;
        }
        setFileErrors((prev) => ({ ...prev, [zone]: '' }));
        setDocuments((prev) => ({ ...prev, [zone]: file }));
      }
    },
    [validateFile]
  );

  const removeFile = useCallback((zone: 'receipt' | 'medicalCert' | 'other', index?: number) => {
    if (zone === 'other' && index !== undefined) {
      setDocuments((prev) => ({ ...prev, other: prev.other.filter((_, i) => i !== index) }));
    } else {
      setDocuments((prev) => ({ ...prev, [zone]: zone === 'other' ? [] : null }));
    }
    setFileErrors((prev) => ({ ...prev, [zone]: '' }));
  }, []);

  const handleDragOver = useCallback((e: React.DragEvent, zone: 'receipt' | 'medicalCert' | 'other') => {
    e.preventDefault();
    setDragOver((prev) => ({ ...prev, [zone]: true }));
  }, []);

  const handleDragLeave = useCallback((e: React.DragEvent, zone: 'receipt' | 'medicalCert' | 'other') => {
    e.preventDefault();
    setDragOver((prev) => ({ ...prev, [zone]: false }));
  }, []);

  const handleDrop = useCallback(
    (e: React.DragEvent, zone: 'receipt' | 'medicalCert' | 'other') => {
      e.preventDefault();
      setDragOver((prev) => ({ ...prev, [zone]: false }));
      handleFileSelect(zone, e.dataTransfer.files);
    },
    [handleFileSelect]
  );

  // --- Submit / Save ---

  const resetForm = useCallback(() => {
    setForm(INITIAL_FORM);
    setDocuments(INITIAL_DOCUMENTS);
    setFileErrors(INITIAL_ERRORS);
    setStep(1);
  }, []);

  const handleSubmit = useCallback(async () => {
    setSubmitting(true);
    try {
      const claim = await createClaim({
        diseaseCategory: form.diseaseCategory as DiseaseCategory,
        diseaseDetails: form.diseaseDetails,
        hospitalName: form.hospitalName,
        treatmentDate: form.treatmentDate,
        receiptAmount: parseFloat(form.receiptAmount),
        claimAmount: parseFloat(form.claimAmount),
        remarks: form.remarks,
      });

      if (documents.receipt) {
        await addDocument(claim.id, {
          type: 'receipt',
          fileName: documents.receipt.name,
          fileSize: documents.receipt.size,
        });
      }
      if (documents.medicalCert) {
        await addDocument(claim.id, {
          type: 'medical_cert',
          fileName: documents.medicalCert.name,
          fileSize: documents.medicalCert.size,
        });
      }
      for (const file of documents.other) {
        await addDocument(claim.id, {
          type: 'other',
          fileName: file.name,
          fileSize: file.size,
        });
      }

      await submitClaim(claim.id);

      resetForm();
      setActiveTab('history');
      toast('success', t('medicalClaims.toast.submitSuccess'));
    } catch {
      toast('error', t('medicalClaims.toast.submitError'));
    } finally {
      setSubmitting(false);
    }
  }, [form, documents, createClaim, addDocument, submitClaim, resetForm, toast, t]);

  const handleSaveDraft = useCallback(async () => {
    setSubmitting(true);
    try {
      const claim = await createClaim({
        diseaseCategory: form.diseaseCategory as DiseaseCategory,
        diseaseDetails: form.diseaseDetails,
        hospitalName: form.hospitalName,
        treatmentDate: form.treatmentDate,
        receiptAmount: parseFloat(form.receiptAmount) || 0,
        claimAmount: parseFloat(form.claimAmount) || 0,
        remarks: form.remarks,
      });

      if (documents.receipt) {
        await addDocument(claim.id, {
          type: 'receipt',
          fileName: documents.receipt.name,
          fileSize: documents.receipt.size,
        });
      }
      if (documents.medicalCert) {
        await addDocument(claim.id, {
          type: 'medical_cert',
          fileName: documents.medicalCert.name,
          fileSize: documents.medicalCert.size,
        });
      }
      for (const file of documents.other) {
        await addDocument(claim.id, {
          type: 'other',
          fileName: file.name,
          fileSize: file.size,
        });
      }

      await saveDraft(claim.id);

      resetForm();
      setActiveTab('history');
      toast('success', t('medicalClaims.toast.draftSaved'));
    } catch {
      toast('error', t('medicalClaims.toast.saveError'));
    } finally {
      setSubmitting(false);
    }
  }, [form, documents, createClaim, addDocument, saveDraft, resetForm, toast, t]);

  // --- Filter claims ---

  const filteredClaims = claims.filter((c) => {
    if (statusFilter === 'all') return true;
    if (statusFilter === 'pending') {
      return ['submitted', 'pending_manager', 'pending_hr', 'processing'].includes(c.status);
    }
    return c.status === statusFilter;
  });

  // --- Computed ---

  const usagePercent = summary.annualLimit > 0
    ? Math.min(100, Math.round((summary.usedAmount / summary.annualLimit) * 100))
    : 0;

  const claimAmountNum = parseFloat(form.claimAmount) || 0;
  const withinLimit = claimAmountNum <= summary.remainingAmount;

  // --- Loading state ---

  if (loading) {
    return (
      <div className="space-y-4 p-4">
        <Skeleton className="h-10 w-64" />
        <div className="grid grid-cols-1 sm:grid-cols-3 gap-4">
          <Skeleton className="h-32" />
          <Skeleton className="h-32" />
          <Skeleton className="h-32" />
        </div>
      </div>
    );
  }

  // --- Tab definitions ---

  const tabItems = [
    { key: 'overview', label: t('medicalClaims.tabs.overview') },
    { key: 'newClaim', label: t('medicalClaims.tabs.newClaim') },
    { key: 'history', label: t('medicalClaims.tabs.history') },
  ];

  // --- Render: Step Indicator ---

  const renderStepIndicator = () => {
    const steps = [
      { num: 1, label: t('medicalClaims.form.stepInfo') },
      { num: 2, label: t('medicalClaims.form.stepDocuments') },
      { num: 3, label: t('medicalClaims.form.stepReview') },
    ];

    return (
      <div className="flex items-center justify-center mb-8">
        {steps.map((s, i) => {
          const isActive = step >= s.num;
          const isComplete = step > s.num;
          return (
            <div key={s.num} className="flex items-center">
              <div className="flex flex-col items-center">
                <div
                  className={`flex h-8 w-8 items-center justify-center rounded-full text-sm font-medium ${
                    isActive
                      ? 'bg-cg-red text-white'
                      : 'bg-gray-200 text-gray-500'
                  }`}
                >
                  {isComplete ? <Check className="h-4 w-4" /> : s.num}
                </div>
                <span
                  className={`mt-1 text-xs ${
                    isActive ? 'text-cg-red font-medium' : 'text-gray-400'
                  }`}
                >
                  {s.label}
                </span>
              </div>
              {i < steps.length - 1 && (
                <div
                  className={`mx-2 h-0.5 w-12 sm:w-20 ${
                    step > s.num ? 'bg-cg-red' : 'bg-gray-200'
                  }`}
                />
              )}
            </div>
          );
        })}
      </div>
    );
  };

  // --- Render: Upload Zone ---

  const renderUploadZone = (
    zone: 'receipt' | 'medicalCert' | 'other',
    label: string,
    required: boolean,
    file: File | null,
    inputRef: React.RefObject<HTMLInputElement | null>,
    multiple = false
  ) => {
    const isDragActive = dragOver[zone];
    const error = fileErrors[zone];
    const otherFiles = zone === 'other' ? documents.other : [];

    return (
      <div className="space-y-2">
        <label className="block text-sm font-medium text-gray-700">
          {label}
