          {detailClaim.documents.length > 0 && (
            <div>
              <h4 className="text-sm font-medium text-gray-700 mb-2">
                {t('medicalClaims.detail.documents')}
              </h4>
              <ul className="space-y-2">
                {detailClaim.documents.map((doc) => (
                  <li key={doc.id} className="flex items-center gap-2 rounded-lg border p-2">
                    <FileText className="h-4 w-4 text-gray-400 shrink-0" />
                    <span className="text-sm truncate flex-1">{doc.fileName}</span>
                    <span className="text-xs text-gray-400">{formatFileSize(doc.fileSize)}</span>
                  </li>
                ))}
              </ul>
            </div>
          )}

          {/* Approval Timeline */}
          {detailClaim.approvalSteps.length > 0 && (
            <div>
              <h4 className="text-sm font-medium text-gray-700 mb-3">
                {t('medicalClaims.detail.approvalTimeline')}
              </h4>
              <div className="relative ml-3">
                {detailClaim.approvalSteps.map((as, i) => {
                  const isLast = i === detailClaim.approvalSteps.length - 1;
                  let dotColor = 'bg-gray-300';
                  let icon = null;

                  if (as.status === 'approved') {
                    dotColor = 'bg-green-500';
                    icon = <Check className="h-3 w-3 text-white" />;
                  } else if (as.status === 'pending') {
                    dotColor = 'bg-yellow-400';
                    icon = <Clock className="h-3 w-3 text-white" />;
                  } else if (as.status === 'rejected') {
                    dotColor = 'bg-red-500';
                    icon = <X className="h-3 w-3 text-white" />;
                  }

                  return (
                    <div key={as.step} className="relative flex gap-4 pb-6">
                      {/* Vertical line */}
                      {!isLast && (
                        <div className="absolute left-[9px] top-5 h-full w-0.5 bg-gray-200" />
                      )}
                      {/* Dot */}
                      <div
                        className={`relative z-10 flex h-5 w-5 shrink-0 items-center justify-center rounded-full ${dotColor}`}
                      >
                        {icon}
                      </div>
                      {/* Content */}
                      <div className="min-w-0 flex-1">
                        <div className="flex items-center justify-between">
                          <p className="text-sm font-medium">{as.role}</p>
                          <Badge
                            variant={
                              as.status === 'approved'
                                ? 'success'
                                : as.status === 'rejected'
                                  ? 'error'
                                  : 'warning'
                            }
                          >
                            {t(`medicalClaims.approval.${as.status}`)}
                          </Badge>
                        </div>
                        <p className="text-xs text-gray-500">{as.approverName}</p>
                        {as.date && (
                          <p className="text-xs text-gray-400 mt-0.5">{formatDate(as.date)}</p>
                        )}
                        {as.comment && (
                          <p className="text-xs text-gray-600 mt-1 italic">{as.comment}</p>
                        )}
                      </div>
                    </div>
                  );
                })}
              </div>
            </div>
          )}

          {/* Rejection reason */}
          {detailClaim.rejectionReason && (
            <div className="flex items-start gap-3 rounded-lg border border-red-200 bg-red-50 p-4">
              <AlertCircle className="h-5 w-5 text-red-600 shrink-0 mt-0.5" />
              <div>
                <p className="text-sm font-medium text-red-800">
                  {t('medicalClaims.detail.rejectionReason')}
                </p>
                <p className="text-sm text-red-700 mt-1">{detailClaim.rejectionReason}</p>
              </div>
            </div>
          )}
        </div>
      </Modal>
    );
  };

  // --- Main Render ---

  return (
    <div className="space-y-6">
      <div className="flex items-center gap-3">
        <Heart className="h-6 w-6 text-cg-red" />
        <h1 className="text-xl font-bold text-cg-dark sm:text-2xl">
          {t('medicalClaims.title')}
        </h1>
      </div>

      <Tabs
        tabs={tabItems}
        activeTab={activeTab}
        onTabChange={(key) => setActiveTab(key as ActiveTab)}
      />

      <div className="mt-4">
        {activeTab === 'overview' && renderOverview()}
        {activeTab === 'newClaim' && renderNewClaim()}
        {activeTab === 'history' && renderHistory()}
      </div>

      {renderDetailModal()}
    </div>
  );
}

'use client';

import { useState } from 'react';
import { useTranslations } from 'next-intl';
import { Clock, Plus, AlertTriangle } from 'lucide-react';
import { Card, CardHeader, CardTitle, CardContent } from '@/components/ui/card';
import { Badge } from '@/components/ui/badge';
import { Button } from '@/components/ui/button';
import { Tabs } from '@/components/ui/tabs';
import { Modal } from '@/components/ui/modal';
import { FormField } from '@/components/ui/form-field';
import { Skeleton } from '@/components/ui/skeleton';
import { useOvertime, type OTStatus, type OTType } from '@/hooks/use-overtime';
import { formatCurrency } from '@/lib/date';

const STATUS_VARIANT: Record<OTStatus, 'neutral' | 'info' | 'success' | 'warning' | 'error'> = {
  pending: 'warning', approved: 'success', completed: 'success', rejected: 'error', cancelled: 'neutral',
};

export function OvertimePage() {
  const t = useTranslations('overtime');
  const tCommon = useTranslations('common');
  const { requests, loading, stats, submitRequest, cancelRequest } = useOvertime();
  const [activeTab, setActiveTab] = useState('summary');
  const [showCreateModal, setShowCreateModal] = useState(false);
  const [form, setForm] = useState({ date: '', startTime: '18:00', endTime: '20:00', reason: '', type: 'weekday' as OTType });

  const tabs = [
    { key: 'summary', label: t('summary') },
    { key: 'request', label: t('newRequest') },
    { key: 'history', label: t('history') },
  ];

  if (loading) {
    return <div className="space-y-4">{[1, 2, 3].map((i) => <Skeleton key={i} className="h-20 w-full" />)}</div>;
  }

  const handleSubmit = async () => {
    const start = parseInt(form.startTime.split(':')[0]);
    const end = parseInt(form.endTime.split(':')[0]);
    const hours = end - start;
    const rates: Record<OTType, number> = { weekday: 1.5, weekend: 2.0, holiday: 3.0, night: 1.5 };
    await submitRequest({
      date: form.date, startTime: form.startTime, endTime: form.endTime,
      totalHours: hours, type: form.type, reason: form.reason,
      estimatedAmount: hours * 250 * rates[form.type],
    });
    setShowCreateModal(false);
    setForm({ date: '', startTime: '18:00', endTime: '20:00', reason: '', type: 'weekday' });
  };

  return (
    <>
      <div className="flex flex-col sm:flex-row sm:items-center justify-between mb-6">
        <div>
          <h1 className="text-2xl font-bold text-cg-dark">{t('title')}</h1>
          <p className="text-gray-500 mt-1">{t('subtitle')}</p>
        </div>
        <Button onClick={() => setShowCreateModal(true)} className="mt-4 sm:mt-0">
          <Plus className="h-4 w-4 mr-2" />{t('newRequest')}
        </Button>
      </div>

      <Tabs tabs={tabs} activeTab={activeTab} onTabChange={setActiveTab} className="mb-6" />

      {activeTab === 'summary' && (
        <div className="space-y-6">
          <div className="grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-4 gap-4">
            <Card><CardContent className="p-6 text-center"><p className="text-2xl font-bold text-cg-dark">{stats.weeklyHours}h</p><p className="text-xs text-gray-400">{t('totalHours')} (week)</p></CardContent></Card>
            <Card><CardContent className="p-6 text-center"><p className="text-2xl font-bold text-yellow-600">{stats.pendingCount}</p><p className="text-xs text-gray-400">{t('pendingRequests')}</p></CardContent></Card>
            <Card><CardContent className="p-6 text-center"><p className="text-2xl font-bold text-green-600">{stats.approvedCount}</p><p className="text-xs text-gray-400">{t('approvedRequests')}</p></CardContent></Card>
            <Card><CardContent className="p-6 text-center">
              <p className="text-2xl font-bold text-cg-dark">{stats.maxWeeklyHours - stats.weeklyHours}h</p>
              <p className="text-xs text-gray-400">{t('remainingHours')}</p>
              {stats.weeklyHours > stats.maxWeeklyHours * 0.8 && (
                <div className="flex items-center justify-center gap-1 mt-1 text-xs text-yellow-600">
                  <AlertTriangle className="h-3 w-3" /> Near limit
                </div>
              )}
            </CardContent></Card>
          </div>

          <Card>
            <CardHeader><CardTitle>{t('typesAndRates')}</CardTitle></CardHeader>
            <CardContent>
              <div className="grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-4 gap-3">
                {(['weekday', 'weekend', 'holiday', 'night'] as OTType[]).map((type) => (
                  <div key={type} className="p-3 bg-gray-50 rounded-lg">
                    <p className="text-sm font-medium">{t(`type.${type}` as never)}</p>
                  </div>
                ))}
              </div>
            </CardContent>
          </Card>

          <Card>
            <CardHeader><CardTitle>{t('recentRequests')}</CardTitle></CardHeader>
            <CardContent>
              {requests.length === 0 ? (
                <p className="text-sm text-gray-500 text-center py-8">{t('noRequests')}</p>
              ) : (
                <div className="space-y-2">
                  {requests.slice(0, 5).map((req) => (
                    <div key={req.id} className="flex items-center justify-between p-3 bg-gray-50 rounded-lg">
                      <div>
                        <p className="text-sm font-medium">{req.date} ({req.startTime} - {req.endTime})</p>
                        <p className="text-xs text-gray-500">{req.reason}</p>
                      </div>
                      <div className="text-right">
                        <Badge variant={STATUS_VARIANT[req.status]}>{t(`status.${req.status}` as never)}</Badge>
                        <p className="text-xs text-gray-500 mt-1">{req.totalHours}h | {formatCurrency(req.estimatedAmount)}</p>
                      </div>
                    </div>
                  ))}
                </div>
              )}
            </CardContent>
          </Card>
        </div>
      )}

      {activeTab === 'history' && (
        <Card>
          <CardContent className="p-0">
            <div className="overflow-x-auto">
              <table className="w-full text-sm">
                <thead>
                  <tr className="border-b bg-gray-50">
                    <th className="text-left py-3 px-4 text-xs font-medium text-gray-400 uppercase">{t('date')}</th>
                    <th className="text-center py-3 px-4 text-xs font-medium text-gray-400 uppercase">{t('time')}</th>
                    <th className="text-center py-3 px-4 text-xs font-medium text-gray-400 uppercase">{t('totalHours')}</th>
                    <th className="text-left py-3 px-4 text-xs font-medium text-gray-400 uppercase">{t('type.weekday')}</th>
                    <th className="text-right py-3 px-4 text-xs font-medium text-gray-400 uppercase">{t('amount')}</th>
                    <th className="text-center py-3 px-4 text-xs font-medium text-gray-400 uppercase">Status</th>
                    <th className="text-center py-3 px-4 text-xs font-medium text-gray-400 uppercase"></th>
                  </tr>
                </thead>
                <tbody>
                  {requests.map((req) => (
                    <tr key={req.id} className="border-b last:border-0 hover:bg-gray-50">
                      <td className="py-3 px-4">{req.date}</td>
                      <td className="py-3 px-4 text-center">{req.startTime} - {req.endTime}</td>
                      <td className="py-3 px-4 text-center">{req.totalHours}h</td>
                      <td className="py-3 px-4">{t(`type.${req.type}` as never)}</td>
                      <td className="py-3 px-4 text-right">{formatCurrency(req.estimatedAmount)}</td>
                      <td className="py-3 px-4 text-center"><Badge variant={STATUS_VARIANT[req.status]}>{t(`status.${req.status}` as never)}</Badge></td>
                      <td className="py-3 px-4 text-center">
                        {req.status === 'pending' && <Button size="sm" variant="ghost" className="text-red-500" onClick={() => cancelRequest(req.id)}>{t('cancelRequest')}</Button>}
                      </td>
                    </tr>
                  ))}
                </tbody>
              </table>
            </div>
          </CardContent>
        </Card>
      )}

      {activeTab === 'request' && (
        <Card>
          <CardHeader><CardTitle>{t('newRequest')}</CardTitle></CardHeader>
          <CardContent>
            <div className="max-w-2xl space-y-4">
              <FormField label={t('date')} name="otDate" type="date" value={form.date} onChange={(v) => setForm((p) => ({ ...p, date: v }))} required />
              <div className="grid grid-cols-1 sm:grid-cols-2 gap-4">
                <FormField label={t('startTime')} name="startTime" value={form.startTime} onChange={(v) => setForm((p) => ({ ...p, startTime: v }))} required />
                <FormField label={t('endTime')} name="endTime" value={form.endTime} onChange={(v) => setForm((p) => ({ ...p, endTime: v }))} required />
              </div>
              <FormField label="Type" name="otType" type="select" value={form.type} onChange={(v) => setForm((p) => ({ ...p, type: v as OTType }))}
                options={[{ value: 'weekday', label: t('type.weekday') }, { value: 'weekend', label: t('type.weekend') }, { value: 'holiday', label: t('type.holiday') }]} />
              <FormField label={t('reason')} name="reason" type="textarea" value={form.reason} onChange={(v) => setForm((p) => ({ ...p, reason: v }))} required />
              <div className="flex justify-end gap-3 pt-2">
                <Button variant="outline" onClick={() => setActiveTab('summary')}>{tCommon('cancel')}</Button>
                <Button onClick={handleSubmit} disabled={!form.date || !form.reason}>{t('submit')}</Button>
              </div>
            </div>
          </CardContent>
        </Card>
      )}

      <Modal open={showCreateModal} onClose={() => setShowCreateModal(false)} title={t('newRequest')}>
        <div className="space-y-4">
          <FormField label={t('date')} name="otDate" type="date" value={form.date} onChange={(v) => setForm((p) => ({ ...p, date: v }))} required />
          <div className="grid grid-cols-2 gap-4">
            <FormField label={t('startTime')} name="startTime" value={form.startTime} onChange={(v) => setForm((p) => ({ ...p, startTime: v }))} required />
            <FormField label={t('endTime')} name="endTime" value={form.endTime} onChange={(v) => setForm((p) => ({ ...p, endTime: v }))} required />
          </div>
          <FormField label="Type" name="otType" type="select" value={form.type} onChange={(v) => setForm((p) => ({ ...p, type: v as OTType }))}
            options={[{ value: 'weekday', label: t('type.weekday') }, { value: 'weekend', label: t('type.weekend') }, { value: 'holiday', label: t('type.holiday') }]} />
          <FormField label={t('reason')} name="reason" type="textarea" value={form.reason} onChange={(v) => setForm((p) => ({ ...p, reason: v }))} required />
        </div>
        <div className="flex justify-end gap-3 mt-6">
          <Button variant="outline" onClick={() => setShowCreateModal(false)}>{tCommon('cancel')}</Button>
          <Button onClick={handleSubmit} disabled={!form.date || !form.reason}>{t('submit')}</Button>
        </div>
      </Modal>
    </>
  );
}

'use client';

import { useState } from 'react';
import { useTranslations } from 'next-intl';
import { BookOpen, Plus, CheckCircle, Clock, Circle } from 'lucide-react';
import { Card, CardHeader, CardTitle, CardContent } from '@/components/ui/card';
import { Badge } from '@/components/ui/badge';
import { Button } from '@/components/ui/button';
import { Tabs } from '@/components/ui/tabs';
import { Skeleton } from '@/components/ui/skeleton';
import { useIdp, type ActionStatus } from '@/hooks/use-idp';

const ACTION_ICON: Record<ActionStatus, React.ReactNode> = {
  completed: <CheckCircle className="h-4 w-4 text-green-500" />,
  in_progress: <Clock className="h-4 w-4 text-yellow-500" />,
  not_started: <Circle className="h-4 w-4 text-gray-300" />,
};

export function IdpPage() {
  const t = useTranslations('idp');
  const { plan, gaps, loading, updateActionStatus } = useIdp();
  const [activeTab, setActiveTab] = useState('gap');

  const tabs = [
    { key: 'gap', label: t('gapAnalysis') },
    { key: 'actions', label: t('developmentActions') },
    { key: 'progress', label: t('progressTracking') },
  ];

  if (loading) {
    return <div className="space-y-4">{[1, 2, 3].map((i) => <Skeleton key={i} className="h-32 w-full" />)}</div>;
  }

  return (
    <>
      <div className="mb-6">
        <h1 className="text-2xl font-bold text-cg-dark">{t('title')}</h1>
        <p className="text-gray-500 mt-1">{t('subtitle')}</p>
      </div>

      {plan && (
        <div className="grid grid-cols-1 sm:grid-cols-3 gap-4 mb-6">
          <Card><CardContent className="p-6 text-center"><p className="text-2xl font-bold text-cg-dark">{plan.overallProgress}%</p><p className="text-xs text-gray-400">{t('overallProgress')}</p></CardContent></Card>
          <Card><CardContent className="p-6 text-center"><p className="text-2xl font-bold text-green-600">{plan.actions.filter((a) => a.status === 'completed').length}/{plan.actions.length}</p><p className="text-xs text-gray-400">{t('completedActions')}</p></CardContent></Card>
          <Card><CardContent className="p-6 text-center">
            <div className="flex items-center justify-center gap-2">
              {plan.employeeSignOff ? <CheckCircle className="h-4 w-4 text-green-500" /> : <Circle className="h-4 w-4 text-gray-300" />}
              <span className="text-xs">{t('employeeSignOff')}</span>
              {plan.managerSignOff ? <CheckCircle className="h-4 w-4 text-green-500" /> : <Circle className="h-4 w-4 text-gray-300" />}
              <span className="text-xs">{t('managerSignOff')}</span>
            </div>
          </CardContent></Card>
        </div>
      )}

      <Tabs tabs={tabs} activeTab={activeTab} onTabChange={setActiveTab} className="mb-6" />

      {activeTab === 'gap' && (
        <Card>
          <CardHeader><CardTitle>{t('competencyGapDetails')}</CardTitle></CardHeader>
          <CardContent>
            {gaps.length === 0 ? (
              <p className="text-sm text-gray-500 text-center py-8">{t('noCompetencyData')}</p>
            ) : (
              <div className="space-y-4">
                {gaps.map((gap) => (
                  <div key={gap.name} className="flex items-center gap-4">
                    <div className="w-40 text-sm font-medium text-gray-700 truncate">{gap.name}</div>
                    <div className="flex-1">
                      <div className="flex items-center gap-2 mb-1">
                        <span className="text-xs text-gray-400">{t('currentLevel')}: {gap.currentLevel}</span>
                        <span className="text-xs text-gray-400">{t('requiredLevel')}: {gap.requiredLevel}</span>
                        {gap.gap > 0 && <Badge variant={gap.priority === 'high' ? 'error' : gap.priority === 'medium' ? 'warning' : 'success'}>{t('gap')}: {gap.gap}</Badge>}
                      </div>
                      <div className="w-full bg-gray-200 rounded-full h-2 relative">
                        <div className="bg-cg-red h-2 rounded-full" style={{ width: `${(gap.currentLevel / 5) * 100}%` }} />
                        <div className="absolute top-0 h-2 border-r-2 border-dashed border-blue-400" style={{ left: `${(gap.requiredLevel / 5) * 100}%` }} />
                      </div>
                    </div>
                  </div>
                ))}
              </div>
            )}
          </CardContent>
        </Card>
      )}

      {activeTab === 'actions' && plan && (
        <div className="space-y-3">
          {plan.actions.map((action) => (
            <Card key={action.id}>
              <CardContent className="p-5 sm:p-6">
                <div className="flex items-start gap-3">
                  {ACTION_ICON[action.status]}
                  <div className="flex-1">
                    <div className="flex items-center justify-between">
                      <h4 className="text-sm font-semibold text-cg-dark">{action.title}</h4>
                      <Badge variant="neutral">{action.actionType}</Badge>
                    </div>
                    <p className="text-xs text-gray-500 mt-1">{action.description}</p>
                    <div className="flex items-center gap-4 mt-2 text-xs text-gray-400">
                      <span>{action.targetCompetency}</span>
                      <span>{action.startDate} - {action.endDate}</span>
                    </div>
                    <div className="mt-2 w-full bg-gray-200 rounded-full h-1.5">
                      <div className="bg-cg-red h-1.5 rounded-full transition-all" style={{ width: `${action.progress}%` }} />
                    </div>
                  </div>
                  <div className="flex gap-1">
                    {action.status === 'not_started' && (
                      <Button size="sm" variant="outline" onClick={() => updateActionStatus(action.id, 'in_progress')}>Start</Button>
                    )}
                    {action.status === 'in_progress' && (
                      <Button size="sm" variant="outline" onClick={() => updateActionStatus(action.id, 'completed')}>Complete</Button>
                    )}
                  </div>
                </div>
              </CardContent>
            </Card>
          ))}
        </div>
      )}

      {activeTab === 'progress' && plan && (
        <Card>
          <CardHeader><CardTitle>{t('progressByArea')}</CardTitle></CardHeader>
          <CardContent>
            <div className="space-y-6">
              {[...new Set(plan.actions.map((a) => a.targetCompetency))].map((comp) => {
                const actions = plan.actions.filter((a) => a.targetCompetency === comp);
                const avgProgress = Math.round(actions.reduce((sum, a) => sum + a.progress, 0) / actions.length);
                return (
                  <div key={comp}>
                    <div className="flex items-center justify-between mb-2">
                      <span className="text-sm font-medium">{comp}</span>
                      <span className="text-sm text-gray-500">{avgProgress}% ({actions.filter((a) => a.status === 'completed').length}/{actions.length} {t('completed')})</span>
                    </div>
                    <div className="w-full bg-gray-200 rounded-full h-2.5">
                      <div className="bg-cg-red h-2.5 rounded-full transition-all" style={{ width: `${avgProgress}%` }} />
                    </div>
                  </div>
                );
              })}
            </div>
          </CardContent>
        </Card>
      )}
    </>
  );
}

'use client';

import { useTranslations } from 'next-intl';
import { useState } from 'react';
import { TrendingUp, Users, AlertTriangle, Star } from 'lucide-react';
import { Card, CardHeader, CardTitle, CardContent } from '@/components/ui/card';
import { Badge } from '@/components/ui/badge';
import { Tabs } from '@/components/ui/tabs';
import { Skeleton } from '@/components/ui/skeleton';
import { useTalent } from '@/hooks/use-talent';

export function TalentPage() {
