import { useSuccession, type Readiness, type RiskLevel } from '@/hooks/use-succession';

const RISK_VARIANT: Record<RiskLevel, 'error' | 'warning' | 'success'> = { high: 'error', medium: 'warning', low: 'success' };
const READINESS_VARIANT: Record<Readiness, 'success' | 'info' | 'neutral'> = { ready_now: 'success', '1_2_years': 'info', '3_plus_years': 'neutral' };

export function SuccessionPage() {
  const t = useTranslations('succession');

  const { plans, stats, loading } = useSuccession();

  if (loading) {
    return <div className="space-y-4">{[1, 2, 3].map((i) => <Skeleton key={i} className="h-40 w-full" />)}</div>;
  }

  return (
    <>
      <div className="mb-6">
        <h1 className="text-2xl font-bold text-cg-dark">{t('title')}</h1>
        <p className="text-gray-500 mt-1">{t('subtitle')}</p>
      </div>

      <div className="grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-4 gap-4 mb-6">
        <Card><CardContent className="p-6 text-center"><p className="text-2xl font-bold text-cg-dark">{stats.totalPositions}</p><p className="text-xs text-gray-400">{t('criticalPositions')}</p></CardContent></Card>
        <Card><CardContent className="p-6 text-center"><p className="text-2xl font-bold text-cg-red">{stats.highRisk}</p><p className="text-xs text-gray-400">{t('highRisk')}</p></CardContent></Card>
        <Card><CardContent className="p-6 text-center"><p className="text-2xl font-bold text-cg-info">{stats.coverageRatio}%</p><p className="text-xs text-gray-400">{t('coverageRatio')}</p></CardContent></Card>
        <Card><CardContent className="p-6 text-center"><p className="text-2xl font-bold text-green-600">{stats.readyNowRatio}%</p><p className="text-xs text-gray-400">{t('readyNowRatio')}</p></CardContent></Card>
      </div>

      <div className="space-y-6">
        {plans.map((plan) => (
          <Card key={plan.id}>
            <CardContent className="p-6">
              <div className="flex flex-col lg:flex-row lg:items-start gap-6">
                {/* Position & Incumbent */}
                <div className="lg:w-1/3">
                  <div className="flex items-center gap-3 mb-3">
                    <Shield className="h-5 w-5 text-cg-dark" />
                    <div>
                      <h3 className="font-semibold text-cg-dark">{plan.positionTitle}</h3>
                      <p className="text-xs text-gray-500">{plan.department}</p>
                    </div>
                  </div>
                  <div className="flex items-center gap-2 mb-2">
                    {plan.incumbentPhoto && <img src={plan.incumbentPhoto} alt="" className="w-8 h-8 rounded-full" />}
                    <div>
                      <p className="text-sm font-medium">{plan.incumbentName}</p>
                      <p className="text-xs text-gray-400">{plan.yearsInRole} {t('yearsInRole')}</p>
                    </div>
                  </div>
                  <div className="flex items-center gap-2 mt-2">
                    <Badge variant={RISK_VARIANT[plan.riskLevel]}>{t(`flightRisk.${plan.riskLevel}` as never)}</Badge>
                    <span className="text-xs text-gray-500">{plan.riskReason}</span>
                  </div>
                </div>

                {/* Successors */}
                <div className="flex-1">
                  <h4 className="text-sm font-semibold text-gray-700 mb-3">{t('identifiedSuccessors')} ({plan.successors.length})</h4>
                  {plan.successors.length === 0 ? (
                    <p className="text-sm text-gray-500">{t('noSuccessorsIdentified')}</p>
                  ) : (
                    <div className="space-y-3">
                      {plan.successors.map((s) => (
                        <div key={s.id} className="flex items-center gap-3 p-3 bg-gray-50 rounded-lg">
                          {s.photo && <img src={s.photo} alt="" className="w-8 h-8 rounded-full" />}
                          <div className="flex-1 min-w-0">
                            <p className="text-sm font-medium truncate">{s.name}</p>
                            <p className="text-xs text-gray-500">{s.position} - {s.department}</p>
                          </div>
                          <Badge variant={READINESS_VARIANT[s.readiness]}>
                            {s.readiness === 'ready_now' ? t('readyNow') : s.readiness === '1_2_years' ? t('ready1To2Years') : t('ready3PlusYears')}
                          </Badge>
                          {s.gaps.length > 0 && (
                            <div className="hidden sm:flex gap-1">
                              {s.gaps.map((g) => <Badge key={g} variant="warning">{g}</Badge>)}
                            </div>
                          )}
                        </div>
                      ))}
                    </div>
                  )}
                </div>
              </div>
            </CardContent>
          </Card>
        ))}
      </div>
    </>
  );
}

'use client';

import { useState } from 'react';
import { useTranslations } from 'next-intl';
import { FileX, CheckCircle, Clock, Circle } from 'lucide-react';
import { Card, CardHeader, CardTitle, CardContent, CardFooter } from '@/components/ui/card';
import { Badge } from '@/components/ui/badge';
import { Button } from '@/components/ui/button';
import { Tabs } from '@/components/ui/tabs';
import { Skeleton } from '@/components/ui/skeleton';
import { useResignation } from '@/hooks/use-resignation';
import { formatCurrency } from '@/lib/date';

export function ResignationPage() {
  const t = useTranslations('resignation');
  const { record, loading, updateClearanceItem, clearanceProgress, submitResignation } = useResignation();
  const [activeTab, setActiveTab] = useState('recording');
  const [showForm, setShowForm] = useState(false);
  const [formData, setFormData] = useState({ lastWorkingDate: '', reason: '', handoverNotes: '' });

  const handleSubmitResignation = async () => {
    if (!formData.lastWorkingDate || !formData.reason) return;
    await submitResignation(formData);
    setShowForm(false);
    setFormData({ lastWorkingDate: '', reason: '', handoverNotes: '' });
  };

  const tabs = [
    { key: 'recording', label: t('tabRecording') },
    { key: 'clearance', label: t('tabClearance') },
    { key: 'settlement', label: t('tabSettlement') },
  ];

  if (loading) {
    return <div className="space-y-4">{[1, 2, 3].map((i) => <Skeleton key={i} className="h-40 w-full" />)}</div>;
  }

  if (!record) {
    return (
      <>
        <div className="mb-6">
          <h1 className="text-2xl font-bold text-cg-dark">{t('title')}</h1>
        </div>
        {showForm ? (
          <Card>
            <CardHeader><CardTitle>Start Resignation Process</CardTitle></CardHeader>
            <CardContent>
              <div className="space-y-4">
                <div className="space-y-1">
                  <label htmlFor="lastWorkingDate" className="block text-sm font-medium text-gray-700">
                    Last Working Date <span className="text-cg-error ml-0.5">*</span>
                  </label>
                  <input
                    id="lastWorkingDate"
                    type="date"
                    value={formData.lastWorkingDate}
                    onChange={(e) => setFormData((p) => ({ ...p, lastWorkingDate: e.target.value }))}
                    className="w-full rounded-lg border border-gray-300 px-3 py-2 text-sm focus:border-cg-red focus:outline-none focus:ring-1 focus:ring-cg-red"
                  />
                </div>
                <div className="space-y-1">
                  <label htmlFor="reason" className="block text-sm font-medium text-gray-700">
                    Reason <span className="text-cg-error ml-0.5">*</span>
                  </label>
                  <textarea
                    id="reason"
                    value={formData.reason}
                    onChange={(e) => setFormData((p) => ({ ...p, reason: e.target.value }))}
                    rows={3}
                    placeholder="Please provide your reason for resignation..."
                    className="w-full rounded-lg border border-gray-300 px-3 py-2 text-sm focus:border-cg-red focus:outline-none focus:ring-1 focus:ring-cg-red resize-y min-h-[80px]"
                  />
                </div>
                <div className="space-y-1">
                  <label htmlFor="handoverNotes" className="block text-sm font-medium text-gray-700">Handover Notes</label>
                  <textarea
                    id="handoverNotes"
                    value={formData.handoverNotes}
                    onChange={(e) => setFormData((p) => ({ ...p, handoverNotes: e.target.value }))}
                    rows={3}
                    placeholder="Notes about knowledge transfer and pending tasks..."
                    className="w-full rounded-lg border border-gray-300 px-3 py-2 text-sm focus:border-cg-red focus:outline-none focus:ring-1 focus:ring-cg-red resize-y min-h-[80px]"
                  />
                </div>
              </div>
              <div className="flex justify-end gap-3 mt-6">
                <Button variant="outline" onClick={() => setShowForm(false)}>Cancel</Button>
                <Button onClick={handleSubmitResignation} disabled={!formData.lastWorkingDate || !formData.reason}>
                  Submit Resignation
                </Button>
              </div>
            </CardContent>
          </Card>
        ) : (
          <Card>
            <CardContent className="py-16 text-center">
              <FileX className="h-16 w-16 text-gray-300 mx-auto mb-4" />
              <h2 className="text-lg font-semibold text-cg-dark mb-2">{t('noResignation')}</h2>
              <p className="text-gray-500 mb-4">{t('noResignationDesc')}</p>
              <Button onClick={() => setShowForm(true)}>{t('startResignation')}</Button>
            </CardContent>
          </Card>
        )}
      </>
    );
  }

  return (
    <>
      <div className="mb-6">
        <h1 className="text-2xl font-bold text-cg-dark">{t('title')}</h1>
        <p className="text-gray-500 mt-1">{t('subtitle')}</p>
      </div>

      <Tabs tabs={tabs} activeTab={activeTab} onTabChange={setActiveTab} className="mb-6" />

      {activeTab === 'recording' && (
        <div className="space-y-4">
          <Card>
            <CardHeader><CardTitle>{t('resignationDetails')}</CardTitle></CardHeader>
            <CardContent>
              <div className="grid grid-cols-1 sm:grid-cols-2 gap-4 text-sm">
                <div><span className="text-gray-400">{t('resignationDate')}</span><p className="font-medium">{record.resignationDate}</p></div>
                <div><span className="text-gray-400">{t('lastWorkingDate')}</span><p className="font-medium">{record.lastWorkingDate}</p></div>
                <div><span className="text-gray-400">{t('reasonType')}</span><p className="font-medium capitalize">{record.reasonType}</p></div>
                <div><span className="text-gray-400">{t('noticePeriod')}</span><p className="font-medium">{record.noticePeriod} {t('days')}</p></div>
                <div><span className="text-gray-400">{t('status')}</span><Badge variant={record.status === 'completed' ? 'success' : 'warning'}>{record.status}</Badge></div>
                <div><span className="text-gray-400">{t('exitInterview')}</span><p className="font-medium">{record.exitInterviewDate || t('notScheduled')}</p></div>
              </div>
              {record.reasonDetails && (
                <div className="mt-4 p-3 bg-gray-50 rounded-lg">
                  <p className="text-sm text-gray-600">{record.reasonDetails}</p>
                </div>
              )}
            </CardContent>
          </Card>

          {/* Status timeline */}
          <Card>
            <CardContent className="p-6">
              <div className="flex items-center justify-between">
                {['submitted', 'in_progress', 'completed'].map((step, i) => (
                  <div key={step} className="flex items-center flex-1">
                    <div className={`w-8 h-8 rounded-full flex items-center justify-center text-sm font-bold ${
                      ['submitted', 'in_progress', 'completed'].indexOf(record.status) >= i ? 'bg-cg-red text-white' : 'bg-gray-200 text-gray-500'
                    }`}>
                      {i + 1}
                    </div>
                    <span className="text-xs ml-2 capitalize">{step.replace('_', ' ')}</span>
                    {i < 2 && <div className={`flex-1 h-0.5 mx-2 ${['submitted', 'in_progress', 'completed'].indexOf(record.status) > i ? 'bg-cg-red' : 'bg-gray-200'}`} />}
                  </div>
                ))}
              </div>
            </CardContent>
          </Card>
        </div>
      )}

      {activeTab === 'clearance' && (
        <Card>
          <CardHeader>
            <div className="flex items-center justify-between">
              <CardTitle>{t('clearanceProgress')}</CardTitle>
              <span className="text-sm font-bold text-cg-dark">{clearanceProgress}%</span>
            </div>
            <div className="w-full bg-gray-200 rounded-full h-2.5 mt-2">
              <div className="bg-cg-red h-2.5 rounded-full transition-all" style={{ width: `${clearanceProgress}%` }} />
            </div>
          </CardHeader>
          <CardContent>
            <div className="space-y-3">
              {record.clearanceItems.map((item) => (
                <div key={item.id} className="flex items-center gap-3 p-3 bg-gray-50 rounded-lg">
                  {item.status === 'completed' ? <CheckCircle className="h-5 w-5 text-green-500" /> : item.status === 'in_progress' ? <Clock className="h-5 w-5 text-yellow-500" /> : <Circle className="h-5 w-5 text-gray-300" />}
                  <div className="flex-1">
                    <p className="text-sm font-medium">{item.title}</p>
                    <p className="text-xs text-gray-500">{t('responsibleParty')}: {item.responsibleParty}</p>
                    {item.signedOffDate && <p className="text-xs text-green-600">{t('signedOffOn')} {item.signedOffDate}</p>}
                  </div>
                  {item.status !== 'completed' && (
                    <Button size="sm" variant="outline" onClick={() => updateClearanceItem(item.id, 'completed')}>{t('updateStatus')}</Button>
                  )}
                </div>
              ))}
            </div>
          </CardContent>
        </Card>
      )}

      {activeTab === 'settlement' && record.settlement && (
        <Card>
          <CardHeader><CardTitle>{t('finalSettlementSummary')}</CardTitle></CardHeader>
          <CardContent>
            <div className="space-y-4">
              <div>
                <h4 className="text-sm font-semibold text-gray-700 mb-2">{t('earnings')}</h4>
                <div className="space-y-1 text-sm">
                  <div className="flex justify-between"><span>{t('outstandingSalary')}</span><span>{formatCurrency(record.settlement.outstandingSalary)}</span></div>
                  <div className="flex justify-between"><span>{t('leaveEncashment')}</span><span>{formatCurrency(record.settlement.leaveEncashment)}</span></div>
                  <div className="flex justify-between"><span>{t('bonus')}</span><span>{formatCurrency(record.settlement.bonus)}</span></div>
                  <div className="flex justify-between font-semibold border-t pt-1">
                    <span>{t('grossTotal')}</span>
                    <span>{formatCurrency(record.settlement.outstandingSalary + record.settlement.leaveEncashment + record.settlement.bonus)}</span>
                  </div>
                </div>
              </div>
              <div>
                <h4 className="text-sm font-semibold text-gray-700 mb-2">{t('deductions')}</h4>
                <div className="space-y-1 text-sm">
                  <div className="flex justify-between"><span>{t('loansAdvances')}</span><span className="text-red-600">-{formatCurrency(record.settlement.loanDeductions)}</span></div>
                </div>
              </div>
              <div className="border-t pt-3">
                <div className="flex justify-between text-lg font-bold text-cg-dark">
                  <span>{t('netPayable')}</span>
                  <span>{formatCurrency(record.settlement.netPayable)}</span>
                </div>
              </div>
              <div className="bg-blue-50 rounded-lg p-3 text-sm text-blue-800">
                <p className="font-medium">{t('providentFund')}</p>
                <p>{t('pfBalance')}: {formatCurrency(record.settlement.pfBalance)}</p>
                <p className="text-xs mt-1">{t('pfNote')}</p>
              </div>
            </div>
          </CardContent>
        </Card>
      )}
    </>
  );
}

