const STATUS_CONFIG: Record<string, { variant: 'success' | 'warning' | 'error' | 'info' | 'neutral'; icon: typeof CheckCircle }> = {
  present: { variant: 'success', icon: CheckCircle },
  late: { variant: 'warning', icon: AlertTriangle },
