                          {' '} | Corrected: <span className="font-mono font-medium">{req.correctedTime}</span>
                        </p>
                        <p className="text-xs text-gray-400 mt-1">{req.reason}</p>
                        {req.approvedBy && (
                          <p className="text-[10px] text-gray-400 mt-1">Approved by {req.approvedBy}</p>
                        )}
                      </div>
                      <ChevronRight className="h-4 w-4 text-gray-300 flex-shrink-0 mt-3" />
                    </div>
                  ))}
                </div>
              )}
            </CardContent>
          </Card>
        </div>
      )}

      {/* ===== CORRECTION REQUEST MODAL ===== */}
      <Modal open={showCorrectionModal} onClose={() => setShowCorrectionModal(false)} title="Time Correction Request">
        <div className="space-y-4">
          <FormField
            label="Date"
            name="corrDate"
            type="date"
            value={correctionForm.date}
            onChange={(v) => setCorrectionForm((p) => ({ ...p, date: v }))}
            required
          />
          <FormField
            label="Correction Type"
            name="corrType"
            type="select"
            value={correctionForm.type}
            onChange={(v) => setCorrectionForm((p) => ({ ...p, type: v as TimeCorrectionRequest['type'] }))}
            options={[
              { value: 'forgot-clock', label: 'Forgot to Clock In/Out' },
              { value: 'missing-checkin', label: 'Missing Check-in' },
              { value: 'missing-checkout', label: 'Missing Check-out' },
              { value: 'wrong-time', label: 'Wrong Time Recorded' },
            ]}
          />
          <FormField
            label="Corrected Time"
            name="corrTime"
            value={correctionForm.correctedTime}
            placeholder="e.g. 09:00"
            onChange={(v) => setCorrectionForm((p) => ({ ...p, correctedTime: v }))}
            required
          />
          <FormField
            label="Reason"
            name="corrReason"
            type="textarea"
            value={correctionForm.reason}
            placeholder="Explain why the correction is needed..."
            onChange={(v) => setCorrectionForm((p) => ({ ...p, reason: v }))}
            required
          />
        </div>
        <div className="flex justify-end gap-3 mt-6">
          <Button variant="outline" onClick={() => setShowCorrectionModal(false)}>{tCommon('cancel')}</Button>
          <Button
            onClick={handleCorrectionSubmit}
            disabled={!correctionForm.date || !correctionForm.correctedTime || !correctionForm.reason}
          >
            Submit Request
          </Button>
        </div>
      </Modal>
    </div>
  );
}

'use client';

import { useTranslations } from 'next-intl';
import { CalendarDays, ClipboardList, PlusCircle, Clock } from 'lucide-react';
import { cn } from '@/lib/utils';

export type LeaveTabId = 'balances' | 'request' | 'history' | 'calendar';

const TAB_ICONS: Record<LeaveTabId, React.ElementType> = {
  balances: CalendarDays,
  request: PlusCircle,
  history: Clock,
  calendar: ClipboardList,
};

interface LeaveTabsProps {
  activeTab: LeaveTabId;
  onChange: (tab: LeaveTabId) => void;
}

export function LeaveTabs({ activeTab, onChange }: LeaveTabsProps) {
  const t = useTranslations('leave');

  const tabs: { id: LeaveTabId; label: string }[] = [
    { id: 'balances', label: t('balances') },
    { id: 'request', label: t('request') },
    { id: 'history', label: t('history') },
    { id: 'calendar', label: t('calendar') },
  ];

  return (
    <div className="border-b bg-white">
      <div className="max-w-7xl mx-auto px-4 sm:px-6">
        <nav className="flex gap-1 overflow-x-auto -mb-px" aria-label="Leave tabs">
          {tabs.map((tab) => {
            const Icon = TAB_ICONS[tab.id];
            const isActive = activeTab === tab.id;
            return (
              <button
                key={tab.id}
                onClick={() => onChange(tab.id)}
                className={cn(
                  'flex items-center gap-2 px-4 py-3 text-sm font-medium border-b-2 whitespace-nowrap transition-colors',
                  isActive
                    ? 'border-cg-red text-cg-red'
                    : 'border-transparent text-gray-500 hover:text-gray-700 hover:border-gray-300'
                )}
              >
                <Icon className="h-4 w-4" />
                {tab.label}
              </button>
            );
          })}
        </nav>
      </div>
    </div>
  );
}

