@import 'tailwindcss';

@variant dark (&:where(.dark, .dark *));

@theme {
  --color-cg-red: #C8102E;
  --color-cg-dark: #333333;
  --color-cg-light: #F5F5F5;
  --color-cg-success: #28A745;
  --color-cg-warning: #FFC107;
  --color-cg-error: #DC3545;
  --color-cg-info: #17A2B8;
  --color-border: #f0f0f0;
  --font-sans: 'Roboto', 'Noto Sans Thai', sans-serif;

  /* Semantic dark theme tokens */
  --color-surface-primary: #FFFFFF;
  --color-surface-secondary: #F5F5F5;
  --color-surface-tertiary: #F9FAFB;
  --color-text-primary: #333333;
  --color-text-secondary: #6B7280;
  --color-text-muted: #9CA3AF;
  --color-border-default: #f0f0f0;
  --color-border-strong: #D1D5DB;
  --color-cg-red-hover: #a80d26;
}

@layer base {
  .dark {
    --color-surface-primary: #1a1a2e;
    --color-surface-secondary: #16213e;
    --color-surface-tertiary: #1e2a47;
    --color-text-primary: #e4e4e7;
    --color-text-secondary: #a1a1aa;
    --color-text-muted: #71717a;
    --color-border-default: #2d3748;
    --color-border-strong: #4a5568;
    --color-cg-red-hover: #e0334a;
  }
}

@keyframes slide-up {
  from { transform: translateY(100%); }
  to { transform: translateY(0); }
}

@keyframes fade-in {
  from { opacity: 0; }
  to { opacity: 1; }
}

