node -e "
const { chromium } = require('playwright');
(async () => {
  const browser = await chromium.launch({ headless: false, slowMo: 200 });
  const page = await browser.newPage();
  await page.setViewportSize({ width: 1440, height: 900 });

  // Light mode
  await page.goto('http://localhost:3000', { waitUntil: 'networkidle' });
  await page.evaluate(() => { localStorage.setItem('theme','light'); document.documentElement.classList.remove('dark'); });
  await page.reload({ waitUntil: 'networkidle' });
  await page.waitForTimeout(1000);
  await page.screenshot({ path: '/tmp/final-01-light.png' });
  console.log('📸 Light mode');

  // Dark mode via toggle button
  const btn = page.locator('header button[title=\"Light\"]');
  if (await btn.count() > 0) { await btn.click(); } else {
    await page.evaluate(() => { document.documentElement.classList.add('dark'); localStorage.setItem('theme','dark'); });
  }
  await page.waitForTimeout(800);

  const hBg = await page.evaluate(() => window.getComputedStyle(document.querySelector('header')).backgroundColor);
  console.log('Header bg in dark:', hBg);

  await page.screenshot({ path: '/tmp/final-02-dark.png' });
  console.log('📸 Dark mode - navbar');

  await page.screenshot({ path: '/tmp/final-03-dark-header.png', clip: { x: 0, y: 0, width: 1440, height: 70 } });
  await page.screenshot({ path: '/tmp/final-04-dark-sidebar.png', clip: { x: 0, y: 0, width: 240, height: 900 } });

  await browser.close();
})();
" 2>&1 | grep -v "system-reminder"
